import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement
} from 'chart.js';
import { Bar, Pie, Line } from 'react-chartjs-2';
import {
  UsersIcon,
  DocumentTextIcon,
  MapPinIcon,
  ExclamationTriangleIcon,
  ArrowTrendingUpIcon,
  CheckCircleIcon,
  UserIcon,
  ArrowRightOnRectangleIcon,
  CpuChipIcon,
  ChartBarIcon
} from '@heroicons/react/24/outline';
import MLPredictionTab from '../components/admin/MLPredictionTab';
import ComplaintManagement from '../components/admin/ComplaintManagement';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement
);

const GlassCard = ({ children, className = "" }) => (
  <div className={`backdrop-blur-md bg-white/70 border border-white/20 shadow-[0_8px_32px_rgba(0,0,0,0.04)] rounded-[2rem] transition-all duration-500 ${className}`}>
    {children}
  </div>
);

const AdminDashboard = () => {
  const [user, setUser] = useState(null);
  const [selectedTimeRange, setSelectedTimeRange] = useState('7d');
  const [activeTab, setActiveTab] = useState('overview');
  const navigate = useNavigate();

  useEffect(() => {
    // Check if user is logged in and is admin
    const token = localStorage.getItem('token');
    const userData = localStorage.getItem('user');

    if (!token || !userData) {
      navigate('/login');
      return;
    }

    const user = JSON.parse(userData);
    if (user.userType !== 'admin') {
      navigate('/dashboard'); // Redirect non-admin users
      return;
    }

    setUser(user);
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  // Advanced Chart Options
  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false
      },
      tooltip: {
        backgroundColor: '#111827',
        titleFont: { size: 12, weight: 'bold' },
        bodyFont: { size: 11 },
        padding: 12,
        cornerRadius: 12,
        displayColors: false
      }
    },
    scales: {
      x: {
        grid: { display: false },
        ticks: { font: { size: 10, weight: '600' }, color: '#9CA3AF' }
      },
      y: {
        grid: { color: 'rgba(0,0,0,0.03)' },
        ticks: { font: { size: 10, weight: '600' }, color: '#9CA3AF' }
      }
    }
  };

  const complaintsByCategory = {
    labels: ['Infrastructure', 'Sanitation', 'Water Supply', 'Roads', 'Public Safety', 'Electricity'],
    datasets: [
      {
        label: 'Complaints',
        data: [45, 38, 32, 28, 25, 20],
        backgroundColor: [
          '#6366f1', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899', '#3b82f6'
        ],
        borderRadius: 8,
        barThickness: 12
      },
    ],
  };

  const weeklyTrends = {
    labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
    datasets: [
      {
        label: 'Volume',
        data: [12, 19, 15, 25, 22, 30, 18],
        borderColor: '#6366f1',
        backgroundColor: 'rgba(99, 102, 241, 0.1)',
        fill: true,
        tension: 0.4,
        pointRadius: 4,
        pointBackgroundColor: '#fff',
        pointBorderWidth: 2
      },
      {
        label: 'Resolved',
        data: [8, 12, 10, 18, 15, 25, 12],
        borderColor: '#10b981',
        backgroundColor: 'rgba(16, 185, 129, 0.1)',
        fill: true,
        tension: 0.4,
        pointRadius: 4,
        pointBackgroundColor: '#fff',
        pointBorderWidth: 2
      },
    ],
  };

  const severityDistribution = {
    labels: ['Low', 'Medium', 'High', 'Critical'],
    datasets: [
      {
        data: [60, 80, 40, 20],
        backgroundColor: ['#10b981', '#f59e0b', '#f97316', '#ef4444'],
        borderWidth: 0,
        hoverOffset: 15
      },
    ],
  };

  const stats = [
    { name: 'Total Users', value: '1,234', icon: UsersIcon, change: '+12%', color: 'text-indigo-600', bg: 'bg-indigo-50' },
    { name: 'Total Complaints', value: '2,456', icon: DocumentTextIcon, change: '+8%', color: 'text-blue-600', bg: 'bg-blue-50' },
    { name: 'Active Hotspots', value: '15', icon: MapPinIcon, change: '-3%', color: 'text-rose-600', bg: 'bg-rose-50' },
    { name: 'System Accuracy', value: '98.2%', icon: CpuChipIcon, change: 'Optimal', color: 'text-emerald-600', bg: 'bg-emerald-50' },
  ];

  const hotspots = [
    { area: 'Downtown District', complaints: 45, severity: 'High', index: 92 },
    { area: 'Industrial Zone', complaints: 32, severity: 'Medium', index: 78 },
    { area: 'Residential North', complaints: 28, severity: 'Low', index: 65 },
    { area: 'Commercial Center', complaints: 25, severity: 'High', index: 88 }
  ];

  const recentActivity = [
    { type: 'SYSTEM', msg: 'Kernel module updated to v2.4.1', time: '12:04:12' },
    { type: 'INGEST', msg: 'New incident packet received: #CMP-904', time: '12:03:45' },
    { type: 'NEURAL', msg: 'Hotspot detection triggered in Downtown', time: '11:58:22' },
    { type: 'RESOLVE', msg: 'Incident #CMP-882 marked as resolved', time: '11:45:10' },
    { type: 'USER', msg: 'New administrative access granted', time: '11:30:00' }
  ];

  const getSeverityColor = (severity) => {
    switch (severity.toLowerCase()) {
      case 'critical': return 'text-red-600 bg-red-50';
      case 'high': return 'text-orange-600 bg-orange-50';
      case 'medium': return 'text-amber-600 bg-amber-50';
      default: return 'text-emerald-600 bg-emerald-50';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Navigation */}
      <nav className="bg-white shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center">
              <Link to="/" className="text-2xl font-bold text-blue-600">Urban Insights</Link>
              <span className="ml-4 text-sm text-gray-500">Admin Panel</span>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center space-x-2">
                <UserIcon className="h-5 w-5 text-gray-400" />
                <span className="text-sm font-medium text-gray-700">
                  {user?.name || 'Admin'}
                </span>
              </div>
              <button
                onClick={handleLogout}
                className="flex items-center space-x-2 text-gray-700 hover:text-red-600 px-3 py-2 rounded-md text-sm font-medium transition-colors"
              >
                <ArrowRightOnRectangleIcon className="h-5 w-5" />
                <span>Logout</span>
              </button>
            </div>
          </div>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900">Admin Dashboard</h1>
          <p className="text-gray-600 mt-2">Monitor and manage community issues system-wide</p>
        </div>

        {/* Tab Navigation */}
        <div className="border-b border-gray-200 mb-8">
          <nav className="-mb-px flex space-x-8">
            {[
              { id: 'overview', name: 'Analytics Overview', icon: ChartBarIcon },
              { id: 'complaint-management', name: 'Complaint Management', icon: ExclamationTriangleIcon },
              { id: 'ml-prediction', name: 'ML Predictions', icon: CpuChipIcon }
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`${activeTab === tab.id
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                  } whitespace-nowrap py-2 px-1 border-b-2 font-medium text-sm flex items-center`}
              >
                <tab.icon className="h-4 w-4 mr-2" />
                {tab.name}
              </button>
            ))}
          </nav>
        </div>

        {/* Tab Content */}
        {activeTab === 'ml-prediction' ? (
          <MLPredictionTab />
        ) : activeTab === 'complaint-management' ? (
          <ComplaintManagement />
        ) : (
          <div className="space-y-10 animate-in slide-in-from-bottom-4 duration-700">
            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {stats.map((stat, i) => (
                <GlassCard key={i} className="p-6 group hover:scale-[1.03] active:scale-95">
                  <div className="flex justify-between items-start mb-4">
                    <div className={`p-4 rounded-2xl ${stat.bg} ${stat.color} transition-transform group-hover:rotate-12`}>
                      <stat.icon className="h-6 w-6" />
                    </div>
                    <span className="text-[10px] font-black px-2 py-1 bg-white/50 rounded-lg text-gray-500 uppercase tracking-widest">
                      {stat.change}
                    </span>
                  </div>
                  <div>
                    <h3 className="text-sm font-bold text-gray-400 uppercase tracking-tighter mb-1">{stat.name}</h3>
                    <div className="text-3xl font-black text-gray-900 tabular-nums">{stat.value}</div>
                  </div>
                </GlassCard>
              ))}
            </div>

            {/* Main Insights Row */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              {/* Category Distribution - Unique Horizontal Style */}
              <GlassCard className="p-8 lg:col-span-1">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-xl font-bold text-gray-900">Incident Density</h3>
                  <div className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded-md">By Category</div>
                </div>
                <div className="h-64 relative">
                  <Bar
                    data={complaintsByCategory}
                    options={{
                      ...chartOptions,
                      indexAxis: 'y',
                      plugins: { ...chartOptions.plugins, tooltip: { ...chartOptions.plugins.tooltip, enabled: true } }
                    }}
                  />
                </div>
              </GlassCard>

              {/* Weekly Trends - Premium Area Chart */}
              <GlassCard className="p-8 lg:col-span-2 overflow-hidden relative group">
                <div className="absolute top-0 right-0 p-8 opacity-[0.03] group-hover:scale-110 transition-transform duration-1000">
                  <ArrowTrendingUpIcon className="h-64 w-64 text-gray-900" />
                </div>
                <div className="relative">
                  <div className="flex items-center justify-between mb-8">
                    <div>
                      <h3 className="text-xl font-bold text-gray-900">Weekly Incident Flow</h3>
                      <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Reported vs. System Action</p>
                    </div>
                    <div className="flex items-center space-x-6">
                      <div className="flex items-center space-x-2">
                        <span className="h-3 w-3 rounded-full bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.5)]"></span>
                        <span className="text-[10px] font-black text-gray-500 uppercase">Incoming</span>
                      </div>
                      <div className="flex items-center space-x-2">
                        <span className="h-3 w-3 rounded-full bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></span>
                        <span className="text-[10px] font-black text-gray-500 uppercase">Resolved</span>
                      </div>
                    </div>
                  </div>
                  <div className="h-64">
                    <Line data={weeklyTrends} options={chartOptions} />
                  </div>
                </div>
              </GlassCard>
            </div>

            {/* Bottom Intelligence Row */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* High-Risk Zones Grid */}
              <GlassCard className="p-8">
                <div className="flex items-center justify-between mb-10">
                  <h3 className="text-xl font-bold text-gray-900">Zone Criticality Map</h3>
                  <div className="flex items-center">
                    <div className="h-2 w-2 rounded-full bg-red-500 animate-pulse mr-2"></div>
                    <span className="text-[10px] font-black text-red-500 uppercase">Live Hotspots</span>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {hotspots.map((zone, i) => (
                    <div key={i} className="p-6 bg-gray-50/50 border border-gray-100/50 rounded-3xl group hover:border-indigo-100 transition-all cursor-default relative overflow-hidden">
                      <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:scale-110 transition-transform">
                        <MapIcon className="h-16 w-16" />
                      </div>
                      <div className="relative">
                        <div className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest inline-block mb-3 ${getSeverityColor(zone.severity)}`}>
                          {zone.severity}
                        </div>
                        <h4 className="text-xs font-black text-gray-900 mb-1">{zone.area}</h4>
                        <div className="flex items-center justify-between mt-4">
                          <div className="text-lg font-black text-gray-800 tabular-nums">{zone.complaints}</div>
                          <div className="text-right">
                            <span className="text-[9px] font-bold text-gray-400 uppercase block leading-none">Risk Index</span>
                            <span className="text-sm font-black text-gray-900">{zone.index}</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </GlassCard>

              {/* System Intelligence Terminal */}
              <GlassCard className="p-8 bg-gray-900 text-white selection:bg-indigo-500/30">
                <div className="flex items-center justify-between mb-8">
                  <div className="flex items-center">
                    <div className="h-2 w-2 rounded-full bg-emerald-500 mr-2 shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
                    <h3 className="text-xl font-bold tracking-tight">Intelligence Stream</h3>
                  </div>
                  <div className="text-[9px] font-mono text-white/30 uppercase tracking-[0.3em]">Node: ALFA-9</div>
                </div>
                <div className="space-y-4 font-mono">
                  {recentActivity.map((log, i) => (
                    <div key={i} className="flex items-start space-x-4 group p-2 rounded-lg hover:bg-white/[0.02] transition-colors">
                      <span className="text-[10px] text-white/20 mt-1 whitespace-nowrap">{log.time}</span>
                      <span className={`text-[10px] font-black min-w-[60px] ${log.type === 'SYSTEM' ? 'text-blue-400' :
                          log.type === 'NEURAL' ? 'text-purple-400' :
                            log.type === 'RESOLVE' ? 'text-emerald-400' : 'text-amber-400'
                        }`}>[{log.type}]</span>
                      <span className="text-[11px] text-white/80 group-hover:text-white transition-colors">{log.msg}</span>
                    </div>
                  ))}
                </div>
                <div className="mt-8 pt-6 border-t border-white/5 flex justify-between items-center">
                  <div className="flex space-x-2">
                    <div className="h-1 w-8 bg-emerald-500/30 rounded-full overflow-hidden">
                      <div className="h-full bg-emerald-500 w-2/3"></div>
                    </div>
                  </div>
                  <button className="text-[9px] font-black text-indigo-400 hover:text-indigo-300 transition-colors uppercase tracking-[0.2em]">
                    Init Full Audit Trail &rarr;
                  </button>
                </div>
              </GlassCard>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
